#### **1. Node Structure:**
Each node will store a word, its definition, and pointers to the left and right children.

```cpp
struct Node {
    std::string word;
    std::string definition;
    Node* left;
    Node* right;

    Node(const std::string& w, const std::string& d) 
        : word(w), definition(d), left(nullptr), right(nullptr) {}
};
```

#### **2. BST Class:**
We define a `BST` class with methods to insert, search, delete, and traverse the tree.

```cpp
class BST {
private:
    Node* root;

    // Helper functions
    Node* insert(Node* node, const std::string& word, const std::string& definition);
    Node* search(Node* node, const std::string& word);
    Node* deleteNode(Node* node, const std::string& word);
    void inOrderTraversal(Node* node);
    void printDictionary(Node* node);

public:
    BST() : root(nullptr) {}

    void insert(const std::string& word, const std::string& definition);
    bool search(const std::string& word);
    void deleteWord(const std::string& word);
    void printAll();
};
```

#### **3. Insert Function:**
Inserts a new node into the BST based on lexicographical order.

```cpp
Node* BST::insert(Node* node, const std::string& word, const std::string& definition) {
    if (node == nullptr) {
        return new Node(word, definition);
    }

    if (word < node->word) {
        node->left = insert(node->left, word, definition);
    } else if (word > node->word) {
        node->right = insert(node->right, word, definition);
    } else {
        // Word already exists; update definition
        node->definition = definition;
    }

    return node;
}

void BST::insert(const std::string& word, const std::string& definition) {
    root = insert(root, word, definition);
}
```

#### **4. Search Function:**
Searches for a word in the BST and returns its definition.

```cpp
Node* BST::search(Node* node, const std::string& word) {
    if (node == nullptr || node->word == word) {
        return node;
    }

    if (word < node->word) {
        return search(node->left, word);
    } else {
        return search(node->right, word);
    }
}

bool BST::search(const std::string& word) {
    Node* result = search(root, word);
    if (result != nullptr) {
        std::cout << "Definition of \"" << word << "\": " << result->definition << std::endl;
        return true;
    } else {
        std::cout << "Word \"" << word << "\" not found in the dictionary." << std::endl;
        return false;
    }
}
```

#### **5. Delete Function:**
Deletes a word from the BST, handling all cases (leaf node, one child, two children).

```cpp
Node* BST::deleteNode(Node* node, const std::string& word) {
    if (node == nullptr) return node;

    if (word < node->word) {
        node->left = deleteNode(node->left, word);
    } else if (word > node->word) {
        node->right = deleteNode(node->right, word);
    } else {
        // Node with only one child or no child
        if (node->left == nullptr) {
            Node* temp = node->right;
            delete node;
            return temp;
        } else if (node->right == nullptr) {
            Node* temp = node->left;
            delete node;
            return temp;
        }

        // Node with two children: Get the inorder successor (smallest in the right subtree)
        Node* temp = node->right;
        while (temp->left != nullptr) {
            temp = temp->left;
        }

        // Copy the inorder successor's data to this node
        node->word = temp->word;
        node->definition = temp->definition;

        // Delete the inorder successor
        node->right = deleteNode(node->right, temp->word);
    }

    return node;
}

void BST::deleteWord(const std::string& word) {
    root = deleteNode(root, word);
    std::cout << "Word \"" << word << "\" has been deleted from the dictionary." << std::endl;
}
```

#### **6. Print Functions:**
Prints all words in alphabetical order using in-order traversal.

```cpp
void BST::inOrderTraversal(Node* node) {
    if (node == nullptr) return;

    inOrderTraversal(node->left);
