    } else {
        // Word already exists; update the definition
        root->definition = definition;
    }

    return root;
}

// Function to search for a word in the BST
bool search(Node* root, string word, string& definition) {
    if (root == nullptr) {
        return false;
    }

    if (word == root->word) {
        definition = root->definition;
        return true;
    } else if (word < root->word) {
        return search(root->left, word, definition);
    } else {
        return search(root->right, word, definition);
    }
